// Fused GEMM + Bias + ReLU
// A: x [M, K] (fp32, ND, row-major)
// B: w [N, K] (fp32, ND, row-major). For GEMM y = A * B^T + bias, set isTransB = true.
// bias: [N] (fp32)
// C: y [M, N] (fp32)
// tilingGm contains: [helper tiling header][TCubeTiling for matmul]
// We'll fetch TCubeTiling via CopyTiling and also compute post-ops in tiles.

constexpr int32_t BUFFER_NUM = 2;

class KernelGemmAddReluCustom {
public:
    __aicore__ inline KernelGemmAddReluCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR bias, GM_ADDR y)
    {
        xGm_.SetGlobalBuffer((__gm__ float*)x, 0);
        wGm_.SetGlobalBuffer((__gm__ float*)w, 0);
        bGm_.SetGlobalBuffer((__gm__ float*)bias, 0);
        yGm_.SetGlobalBuffer((__gm__ float*)y, 0);
    }

    __aicore__ inline void PostReluProcess(uint32_t totalLen)
    {
        if (totalLen == 0) return;

        // Decide tileLen on device (simple, robust)
        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // 64KB per tile (float): 64 * 1024 / 4 = 16384 elements, aligned to 2048
        const uint32_t baseTile = 16384u;
        const uint32_t ALIGN_ELEMS = 2048u;
        uint32_t tileLen = (totalLen >= baseTile) ? baseTile : totalLen;
        tileLen = (tileLen / ALIGN_ELEMS) * ALIGN_ELEMS;
        if (tileLen == 0u) tileLen = (totalLen < ALIGN_ELEMS) ? totalLen : ALIGN_ELEMS;

        pipe_.InitBuffer(inQueue_, BUFFER_NUM, tileLen * sizeof(float));
        pipe_.InitBuffer(outQueue_, BUFFER_NUM, tileLen * sizeof(float));

        const uint32_t strideElems = blockNum * tileLen;
        uint32_t base = blockIdx * tileLen;
        if (base >= totalLen) return;

        // Prefetch first tile
        uint32_t curLen = totalLen - base;
        if (curLen > tileLen) curLen = tileLen;
        CopyIn(base, curLen);

        while (true) {
            // Prefetch next tile
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen) {
                nextLen = totalLen - nextBase;
                if (nextLen > tileLen) nextLen = tileLen;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = inQueue_.AllocTensor<float>();
        AscendC::DataCopy(yLocal, yGm_[gmOffset], len);
        inQueue_.EnQue(yLocal);
    }

    __aicore__ inline void Compute(uint32_t len)
    {
        AscendC::LocalTensor<float> inLocal = inQueue_.DeQue<float>();
        AscendC::LocalTensor<float> outLocal = outQueue_.AllocTensor<float>();

        // ReLU: y = max(y, 0)
        AscendC::Maxs(outLocal, inLocal, 0.0f, len);

        outQueue_.EnQue<float>(outLocal);
        inQueue_.FreeTensor(inLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> outLocal = outQueue_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], outLocal, len);
        outQueue_.FreeTensor(outLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueue_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> bGm_;
    AscendC::GlobalTensor<float> yGm_;
};

extern "C" __global__ __aicore__ void gemm_add_relu_custom(GM_ADDR x, GM_ADDR w, GM_ADDR bias, GM_ADDR y, GM_ADDR workspace, GM_ADDR tilingGm)
{
#if defined(ASCENDC_CPU_DEBUG)
