    // Heuristic: try to get shape from matmul obj public members (not accessible here), so we rely on helper header.
    // Helper header GemmAddReluCustomTilingData is stored at head of tiling buffer; parse first.
    {
        // Read helper header to get M,N
        optiling::GemmAddReluCustomTilingData helper;
        // Copy helper header from GM to local buffer
        auto helperSize = helper.GetDataSize();
        // Create a temporary local buffer to read the header
        AscendC::TPipe tpipe;
        AscendC::TQue<AscendC::TPosition::VECIN, 1> q;
        const uint32_t elems = (helperSize + sizeof(float) - 1) / sizeof(float);
        tpipe.InitBuffer(q, 1, elems * sizeof(float));
        AscendC::LocalTensor<float> buf = q.AllocTensor<float>();
        AscendC::DataCopy(buf, (__gm__ float*)tilingGm, elems);
        q.EnQue(buf);
        AscendC::LocalTensor<float> rb = q.DeQue<float>();
        // Assuming helper can deserialize from raw buffer
        helper.LoadFromBuffer(rb.GetPtr(0), helperSize);
        M = helper.get_M();
        N = helper.get_N();
        q.FreeTensor(rb);
    }

    const uint32_t totalLen = M * N;
    KernelGemmAddReluCustom postOp;
    postOp.Init(x, w, bias, y);
    postOp.PostReluProcess(totalLen);
}
